950	class TrackingLockProvider implements LockProvider {
951	  private readonly inner = new MemoryLockProvider();
952	  private readonly active = new Map<string, number>();
953	  private readonly maxActive = new Map<string, number>();
954	
955	  async withLock<T>(key: string, fn: () => Promise<T>): Promise<T> {
956	    return this.inner.withLock(key, async () => {
957	      const active = (this.active.get(key) ?? 0) + 1;
958	      this.active.set(key, active);
959	      this.maxActive.set(key, Math.max(this.maxActive.get(key) ?? 0, active));
960	      await Promise.resolve();
961	      try {
962	        return await fn();
963	      } finally {
964	        this.active.set(key, (this.active.get(key) ?? 1) - 1);
965	      }
966	    });
967	  }
968	
969	  maxActiveFor(key: string): number {
970	    return this.maxActive.get(key) ?? 0;
971	  }
972	}
