      })
    );

    expect(monitor.health.v2_clusters.fallback_count_last_24h).toBe(1);
    expect(monitor.cache_health.stale_or_needs_prepare[0].id).toBe("weak-cluster");
    expect(monitor.quality.cluster_stats[0]).toMatchObject({
